1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Array<{ op: "quote"; items: Array<{ type: string }> }>;
14	};
15	
16	type QuoteResult = { premium: number };
17	
18	const quotePremium = (items: Array<{ type: string }>): QuoteResult => {
19	  if (items.length === 0) return { premium: PROCESSING_FEE };
20	  const base = BASE_PREMIUMS[items[0].type];
21	  const firstInsurance = base * FIRST_INSURANCE_RATE;
22	  return { premium: base + firstInsurance + PROCESSING_FEE };
23	};
24	
25	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
26	  const results = scenario.steps.map((step) => quotePremium(step.items));
27	  return { results };
28	};
