41	    expect(result).toEqual({ results: [{ premium: 49 }] });
42	  });
43	
44	  // === Components ===
45	  it.todo("2 runes → 50 G base premium (no block)");
46	  it.todo("3 runes → 60 G base premium (block applies)");
47	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
48	  it.todo("7 runes → 175 G base premium (no block — block requires exactly 3)");
49	
50	  // === Alike components ===
51	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
52	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
53	
54	  // === Item-specific modifiers ===
55	  it.todo("cursed sword (steel, ench 3, newcomer) → 100 + 50 curse + 15 first = 165 + 5 fee = 165 G (matches integration example)");
56	  it.todo("sword with enchantment 5 (newcomer) → 100 + 30 high-ench + 13 first + 5 fee = 148 G");
57	  it.todo("sword with enchantment 4 (newcomer) → no high-ench surcharge: 100 + 10 first + 5 fee = 115 G");
58	  it.todo("cursed sword with enchantment 5 (newcomer) → both surcharges: 100 + 50 + 30 + 18 first + 5 fee = 203 G");
59	
