61	  it.todo("loyalty discount — customer with exactly 2 years → 20% off policy total");
62	  it.todo("loyalty discount does not apply for 1-year customer");
63	  it.todo("follow-up contract — second quote receives 15% discount on policy total");
64	
65	  // === Modifier scope on multi-item policies ===
66	  it.todo("policy with cursed sword + plain amulet → 100 + 60 + 50 curse (item-specific) = 210 before policy-wide and fee");
67	
68	  // === Rounding ===
69	  it.todo("premium that yields 197.5 G → rounded up to 198 G (MHPCO's favor)");
70	  it.todo("payout that yields 350.5 G → rounded down to 350 G (MHPCO's favor)");
71	
72	  // === Claim processing — basic ===
73	  it.todo("standard reimbursement: regular sword (steel, ench 3), damage 500 G → payout 400 G");
74	  it.todo("standard reimbursement: rune (insurance 250 G), damage 200 G → payout 100 G");
75	
76	  // === Claim processing — special clauses ===
77	  it.todo("high enchantment (≥8) damage at 50%: sword ench 8, damage 1000 G → 500 - 100 deductible = 400 G");
78	  it.todo("dragon material full reimbursement: dragon sword ench 5, damage 800 G → 800 - 100 = 700 G");
79	  it.todo("dragon material + ench 9: 50% rule wins then deductible: 500 - 100 = 400 G");
