87	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
88	  it.todo("dragon attack on two swords → each damage entry treated separately with own deductible");
89	  it.todo("more damage entries of a type than policy covers → CLI rejects with non-zero exit");
90	
91	  // === Cap exhaustion ===
92	  it.todo("policy: sword + amulet → insurance sum 1600 G, cap 3200 G");
93	  it.todo("cursed sword premium with modifiers doesn't raise cap (cap based on unmodified insurance value)");
94	  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 G; block affects premium, not insurance sum");
95	  it.todo("sword (cap 2000 G), first claim 1500 → payout 1400, remaining 600");
96	  it.todo("sword (cap 2000 G), second claim 1500 → payout 600, remaining 0");
97	
98	  // === Error cases ===
99	  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
100	  it.todo("claim references item not in policy → CLI exits non-zero with error on stderr");
101	  it.todo("claim with negative damage amount → CLI exits non-zero with error on stderr");
102	
103	  // === Integration examples ===
104	  it.todo("integration: newcomer with cursed sword (steel, ench 3) → 165 G");
105	  it.todo("integration: 3-year customer's second quote, cursed sword (steel, ench 7) → 160 G");
106	});
